static u32 nm_len (cstr nm) {
    if (nm == nullptr) {
        return 0;
    }
    return (u32)std::strlen(nm);
}

static u32 max_nm_len_slots (const EnSlot* slots, u32 slot_count, const StaticParsingManager& mgr, cstr (*get_nm) (const StaticParsingManager&, u16)) {
    u32 mx = 0;
    for (u32 s = 0; s < slot_count; ++s) {
        if (slots[s].m_n == 0) {
            continue;
        }
        u32 ln = nm_len(get_nm(mgr, (u16)s));
        if (ln > mx) {
            mx = ln;
        }
    }
    return mx;
}

static cstr tech_nm (const StaticParsingManager& mgr, u16 idx) {
    const TechStaticDataStruct* a = mgr.get_tech_data();
    if (a == nullptr || idx >= mgr.get_tech_count()) {
        return "";
    }
    return a[idx].name.c_str();
}

static cstr resource_nm (const StaticParsingManager& mgr, u16 idx) {
    const ResourceStaticDataStruct* a = mgr.get_resource_data();
    if (a == nullptr || idx >= mgr.get_resource_count()) {
        return "";
    }
    return a[idx].name.c_str();
}

static cstr building_nm (const StaticParsingManager& mgr, u16 idx) {
    const BuildingStaticDataStruct* a = mgr.get_building_data();
    if (a == nullptr || idx >= mgr.get_building_count()) {
        return "";
    }
    return a[idx].name.c_str();
}

static cstr city_flag_nm (const StaticParsingManager& mgr, u16 idx) {
    const CityFlagStaticDataStruct* a = mgr.get_city_flag_data();
    if (a == nullptr || idx >= mgr.get_city_flag_count()) {
        return "";
    }
    return a[idx].name.c_str();
}

static cstr civ_nm (const StaticParsingManager& mgr, u16 idx) {
    const CivStaticDataStruct* a = mgr.get_civ_data();
    if (a == nullptr || idx >= mgr.get_civ_count()) {
        return "";
    }
    return a[idx].name.c_str();
}

static void pr_en_section (FILE* out, cstr title, const EnSlot* slots, u32 slot_count, const StaticParsingManager& mgr, cstr (*get_prereq_nm) (const StaticParsingManager&, u16), const BruteRunCfg& cfg) {
    u32 mx = max_nm_len_slots(slots, slot_count, mgr, get_prereq_nm);
    u32 pad = mx + 1;
    bool any = false;
    for (u32 s = 0; s < slot_count; ++s) {
        if (slots[s].m_n > 0) {
            any = true;
            break;
        }
    }
    if (!any) {
        return;
    }
    std::fprintf(out, "%s\n\n", title);
    for (u32 s = 0; s < slot_count; ++s) {
        if (slots[s].m_n == 0) {
            continue;
        }
        cstr pn = get_prereq_nm(mgr, (u16)s);
        std::fprintf(out, "%-*s >", pad, pn);
        for (u16 j = 0; j < slots[s].m_n; ++j) {
            u16 ix = slots[s].m_items[j];
            cstr inm = "";
            if (cfg.m_names != nullptr && ix < cfg.m_item_count) {
                inm = cfg.m_names[ix];
            }
            if (j == 0) {
                std::fprintf(out, " %s", inm);
            } else {
                std::fprintf(out, ", %s", inm);
            }
        }
        std::fprintf(out, "\n");
    }
    std::fprintf(out, "\n");
}

