void AssessorBruteWrite::pad_name (char* buf, u32 buf_sz, cstr name) {
    u32 len = (u32)std::strlen(name);
    if (len >= buf_sz) {
        len = buf_sz - 1;
    }
    std::memcpy(buf, name, len);
    buf[len] = '\0';
    for (u32 i = len; i < 28 && i < buf_sz - 1; ++i) {
        buf[i] = ' ';
    }
    if (28 < buf_sz) {
        buf[28] = '\0';
    }
}

void AssessorBruteWrite::emit_req_tok (FILE* out, cstr kind, cstr nm, u8 arg) {
    if (arg != 0) {
        std::fprintf(out, " : %s(%s, %u)", kind, nm, (u32)arg);
    } else {
        std::fprintf(out, " : %s(%s)", kind, nm);
    }
}

void AssessorBruteWrite::emit_reqs (FILE* out, const InferredReqs& ir, const StaticParsingManager& mgr) {
    const TechStaticDataStruct* tech_items = mgr.get_tech_data();
    for (u8 i = 0; i < ir.m_tech_n; ++i) {
        u16 ix = ir.m_tech[i];
        if (tech_items != nullptr && ix < mgr.get_tech_count()) {
            emit_req_tok(out, "tech", tech_items[ix].name.c_str(), 0);
        }
    }
    const ResourceStaticDataStruct* resource_items = mgr.get_resource_data();
    for (u8 i = 0; i < ir.m_resource_n; ++i) {
        u16 ix = ir.m_resource[i];
        if (resource_items != nullptr && ix < mgr.get_resource_count()) {
            emit_req_tok(out, "resource", resource_items[ix].name.c_str(), 0);
        }
    }
    const BuildingStaticDataStruct* building_items = mgr.get_building_data();
    for (u8 i = 0; i < ir.m_building_n; ++i) {
        u16 ix = ir.m_building[i];
        if (building_items != nullptr && ix < mgr.get_building_count()) {
            emit_req_tok(out, "building", building_items[ix].name.c_str(), 1);
        }
    }
    const CityFlagStaticDataStruct* city_flag_items = mgr.get_city_flag_data();
    for (u8 i = 0; i < ir.m_city_flag_n; ++i) {
        u16 ix = ir.m_city_flag[i];
        if (city_flag_items != nullptr && ix < mgr.get_city_flag_count()) {
            emit_req_tok(out, "flag", city_flag_items[ix].name.c_str(), 0);
        }
    }
    const CivStaticDataStruct* civ_items = mgr.get_civ_data();
    for (u8 i = 0; i < ir.m_civ_n; ++i) {
        u16 ix = ir.m_civ[i];
        if (civ_items != nullptr && ix < mgr.get_civ_count()) {
            emit_req_tok(out, "civ", civ_items[ix].name.c_str(), 0);
        }
    }
}

void AssessorBruteWrite::write_readable (FILE* out, const EnablesMap& en, const StaticParsingManager& mgr, const BruteRunCfg& cfg) {
    if (out == nullptr) {
        return;
    }
    pr_en_section(out, "TECHS", en.m_tech, en.m_tech_count, mgr, tech_nm, cfg);
    pr_en_section(out, "RESOURCES", en.m_resource, en.m_resource_count, mgr, resource_nm, cfg);
    pr_en_section(out, "BUILDINGS", en.m_building, en.m_building_count, mgr, building_nm, cfg);
    pr_en_section(out, "FLAGS", en.m_city_flag, en.m_city_flag_count, mgr, city_flag_nm, cfg);
    pr_en_section(out, "CIVS", en.m_civ, en.m_civ_count, mgr, civ_nm, cfg);
}

